Here's a set of **pytest-style unit tests** for the `memoize` decorator. These tests cover:

- **Happy path**: Function is called once, and the result is cached.
- **Edge case**: Multiple calls with the same arguments.
- **Error case**: Non-hashable arguments (like lists) that can't be used as keys in a dictionary.

### File: `test_memoize.py`

```python
import pytest

def memoize(fn):
    cache = {}
    def wrapper(*args):
        if args not in cache:
            cache[args] = fn(*args)
        return cache[args]
    return wrapper

# Test functions
def add(a, b):
    return a + b

def multiply(a, b):
    return a * b

def append_list(lst, item):
    lst.append(item)
    return lst

# Test cases
def test_memoize_happy_path():
    @memoize
    def add(a, b):
        return a + b

    assert add(2, 3) == 5
    assert add(2, 3) == 5  # Should return cached value

def test_memoize_multiple_calls():
    @memoize
    def multiply(a, b):
        return a * b

    assert multiply(2, 3) == 6
    assert multiply(2, 3) == 6  # Should return cached value
    assert multiply(4, 5) == 20
    assert multiply(4, 5) == 20  # Should return cached value

def test_memoize_error_non_hashable_arguments():
    @memoize
    def append_list(lst, item):
        lst.append(item)
        return lst

    with pytest.raises(TypeError, match="unhashable type: 'list'"):
        append_list([1, 2], 3)

def test_memoize_with_kwargs():
    @memoize
    def greet(name, greeting="Hello"):
        return f"{greeting}, {name}!"

    assert greet("Alice") == "Hello, Alice!"
    assert greet("Alice") == "Hello, Alice!"  # Should return cached value
    assert greet("Bob", "Hi") == "Hi, Bob!"
    assert greet("Bob", "Hi") == "Hi, Bob!"  # Should return cached value

def test_memoize_with_mixed_args():
    @memoize
    def combine(a, b, c):
        return a + b + c

    assert combine(1, 2, 3) == 6
    assert combine(1, 2, 3) == 6  # Should return cached value
    assert combine(1, 3, 2) == 6
    assert combine(1, 3, 2) == 6  # Should return cached value
```

### How to Run

Save the code above in a file named `test_memoize.py` and run it with:

```bash
pytest test_memoize.py
```

### Notes

- The `memoize` function works by memoizing the results of function calls based on the arguments passed.
- The `append_list` function is designed to fail because it uses a list, which is unhashable, and thus cannot be used as a key in the cache dictionary.
- The `greet` and `combine` functions test support for keyword arguments and different argument orders respectively.

Let me know if you want to test with more complex objects or use `functools.lru_cache` as a comparison.
